```typescript
function stripCodeBlocks(text: string): string {
    // Remove leading and trailing code block delimiters if present.
    return text
        .replace(/^```(?:json)?\s*/i, '')
        .replace(/\s*```$/, '')
        .trim();
}

function parseJsonIfPossible(strippedText: string): any | null {
    // Check if the stripped text starts with a JSON object or array.
    if (strippedText.startsWith('{') || strippedText.startsWith('[')) {
        try {
            return JSON.parse(strippedText);
        } catch {
            // If parsing fails, return null.
            return null;
        }
    }
    // Return null if the text does not start with a JSON object or array.
    return null;
}

function processText(text: string): any | null {
    const stripped = stripCodeBlocks(text);
    return parseJsonIfPossible(stripped);
}

// Example usage:
const inputText = "```json\n{\n  \"key\": \"value\"\n}\n```";
const result = processText(inputText);
console.log(result); // Output: { key: 'value' }
```

